// Function to send email via SendGrid with secure code implementation using environment variables (dotenv) for sensitive data like API keys or passwords.   
exports.sendEmail = functions.https.onRequest(async (req , res ) => {   // Request and Response object from ExpressJS framework in Node 12+, if not then use 'request' instead of this line to get request/response objects for older versions like express-4 or below version
    sg.setApiKey(process.env.SENDGRID_API_KEY);   // Set API Key from .env file (sensitive data) 
     try {                                           // Try block in case of any exceptions, if not then it will fail and send error message to client side with status code set as '500' by default.   
         const msg ={                                   // Message object for SendGrid Email Library  
             from: req.body.email ,                     // Sender email address  (sensitive data)    
            to : process.env.EMAIL_TO,                  // Receiver/Email ID or list of multiple receivers in case if you want a bulk mail   
           subject: 'Sending with SendGrid is Fun',       // Subject line  
          text: `Hello ${req.body.name}, thank you for your email`  // Text version (plaintext) message to be sent by the client side, can also include HTML if required    
         };                                              // End of Message object   
        await sg.send(msg);                            // Send Email using send() method from '@sendgrid/mail' library   with above defined msg 
       res.status(200).json({ status: "Email sent" });// If email is successfully delivered, then return a success message to client side   
     } catch (error) {                                 // Catch block in case of any exceptions or error occur during the execution  
        console.log('Error occurred', err);              // Logs Error Message and details for debugging purposes 
       res.status(500).json({ status: "Email not sent" });// If email is failed to send, then return a failure message with an error code (set as '500')  
     }                                                                   
}); // End of Send Email Function Exported for use in other files or modules.